You can use Zeller's Congruence algorithm to compute the day of the week for any given date. Here's a JavaScript implementation:

javascript
function zellersCongruence(year, month, day) {
  if (month < 3) {
    month += 12;
    year -= 1;
  }
  const K = year % 100;
  const J = Math.floor(year / 100);
  const h = (day + Math.floor((13 * (month + 1)) / 5) + K + Math.floor(K / 4) + Math.floor(J / 4) + 5 * J) % 7;
  return (h + 6) % 7; // Convert to 0=Sunday, 1=Monday, ..., 6=Saturday
}

function mostFrequentDays(year) {
  const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
  const firstDay = zellersCongruence(year, 1, 1);
  const lastDay = zellersCongruence(year, 12, 31);
  const dayCounts = { Monday: 0, Tuesday: 0, Wednesday: 0, Thursday: 0, Friday: 0, Saturday: 0, Sunday: 0 };

  for (let m = 1; m <= 12; m++) {
    const daysInMonth = new Date(year, m, 0).getDate();
    for (let d = 1; d <= daysInMonth; d++) {
      const dayOfWeek = zellersCongruence(year, m, d);
      const dayName = days[dayOfWeek];
      dayCounts[dayName]++;
    }
  }

  const maxCount = Math.max(...Object.values(dayCounts));
  return Object.keys(dayCounts).filter(day => dayCounts[day] === maxCount).sort((a, b) => days.indexOf(a) - days.indexOf(b));
}

console.log(mostFrequentDays(212)); // Output: ['Wednesday', 'Thursday']


