Instead of iterating through every day of the year, we can observe that the first and last day of the year determine the most frequent days. This is because the days of the week cycle every 7 days. The most frequent days are those that appear 52 times in a non-leap year (52 * 7 = 364) or 52 times for some days and 53 times for others in a leap year. Here's an optimized JavaScript function:

javascript
function mostFrequentDays(year) {
  const days = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
  const isLeap = (year % 400 === 0) || (year % 100 !== 0 && year % 4 === 0);
  const firstDay = zellersCongruence(year, 1, 1);
  const lastDay = zellersCongruence(year, 12, 31);

  if (isLeap) {
    // In a leap year, one extra day occurs
    const extraDay = (firstDay === lastDay) ? firstDay : (firstDay + 1) % 7;
    return [days[firstDay], days[extraDay]].sort((a, b) => days.indexOf(a) - days.indexOf(b));
  } else {
    // In a non-leap year, all days appear exactly 52 times
    return [days[firstDay]];
  }
}

function zellersCongruence(year, month, day) {
  if (month < 3) {
    month += 12;
    year -= 1;
  }
  const K = year % 100;
  const J = Math.floor(year / 100);
  const h = (day + Math.floor((13 * (month + 1)) / 5) + K + Math.floor(K / 4) + Math.floor(J / 4) + 5 * J) % 7;
  return (h + 6) % 7;
}

console.log(mostFrequentDays(212)); // Output: ['Wednesday', 'Thursday']


